# Auto-detect icon key from node label. Returns None if no match.
# Order matters: more specific checks (full extension) run before keyword checks.
def _detect_icon(label):
    l = label.lower()
    if l.endswith(".py"):                          return "python"
    if l.endswith(".sh"):                          return "gnubash"
    # Named runtimes/frameworks before the generic .js file extension check
    if l in ("node.js", "nodejs", "node"):         return "nodedotjs"
    if l in ("vue.js", "vuejs", "vue"):            return "vuedotjs"
    if l in ("next.js", "nextjs"):                 return "nextdotjs"
    if "nuxt" in l:                                return "nuxtdotjs"
    if l.endswith(".js"):                          return "javascript"
    if l.endswith(".md"):                          return "markdown"
    if l.endswith(".json"):                        return "json"
    if "gmail" in l or "imap" in l:               return "gmail"
    if "npm" in l:                                 return "npm"
    if "launchd" in l or "plist" in l:            return "apple"
    if "linkedin" in l and not l.endswith(".py"): return "linkedin"
    if "cowork" in l or "anthropic" in l:         return "anthropic"
    if "openai" in l or "chatgpt" in l:           return "openai"
    if "twilio" in l:                             return "twilio"
    if " aws" in l or l.startswith("aws") or "amazon" in l: return "amazonaws"
    if "slack" in l:                              return "slack"
    if ".net" in l or "dotnet" in l:             return "dotnet"
    if "redis" in l:                             return "redis"
    if "github" in l:                                    return "github"
    if "gitlab" in l:                                    return "gitlab"
    if l.startswith("git") and "github" not in l and "gitlab" not in l: return "git"
    if "spring" in l:                            return "spring"
    if "mariadb" in l:                           return "mariadb"
    if "bitbucket" in l:                         return "bitbucket"
    if "digitalocean" in l:                      return "digitalocean"
    if "firebase" in l:                          return "firebase"
    if "postman" in l:                           return "postman"
    if "java" in l and "javascript" not in l:    return "java"
    # file extension: TypeScript
    if l.endswith(".ts") and not l.endswith(".d.ts"):      return "typescript"
    # Apache-prefixed tech (label often omits "Apache")
    if "cassandra" in l:                                    return "apachecassandra"
    if "couchdb" in l or "couch db" in l:                  return "apachecouchdb"
    if "kafka" in l:                                        return "apachekafka"
    if "airflow" in l:                                      return "apacheairflow"
    if "hadoop" in l:                                       return "apachehadoop"
    if "maven" in l:                                        return "apachemaven"
    if "tomcat" in l:                                       return "apachetomcat"
    if "spark" in l:                                        return "apachespark"
    # Aliases / partial names
    if "postgres" in l:                                     return "postgresql"
    if "mongo" in l:                                        return "mongodb"
    if "elasticsearch" in l or ("elastic" in l and "elasticmail" not in l): return "elasticsearch"
    if "openshift" in l:                                    return "redhatopenshift"
    if "apollo" in l:                                        return "apollographql"
    if "graphql" in l:                                       return "graphql"
    if "openapi" in l:                                      return "openapiinitiative"
    if "k8s" in l or "kubernetes" in l:                    return "kubernetes"
    if "tailwind" in l:                                     return "tailwindcss"
    if "rollup" in l:                                       return "rollupdotjs"
    if "new relic" in l:                                    return "newrelic"
    if "rails" in l:                                         return "rubyonrails"
    if "typescript" in l:                                   return "typescript"
    if l == "go" or "golang" in l:                         return "go"
    if l in ("c#", "csharp", "c sharp"):                   return "csharp"
    if l in ("c++", "cplusplus", "c plus plus"):           return "cplusplus"
    if "azure" in l and "devops" in l:                     return "azuredevops"
    if "azure" in l:                                        return "microsoftazure"
    if "vscode" in l or "vs code" in l or "visual studio code" in l: return "visualstudiocode"
    if "teams" in l and "microsoft" in l:                  return "microsoftteams"
    if "webassembly" in l:                                  return "wasm"
    if "playwright" in l:                                   return "playwright"
    if "salesforce" in l:                                   return "salesforce"
    if "sonarqube" in l or "sonar" in l:                   return "sonarqube"
    if "cockroach" in l:                                    return "cockroachdb"
    if "sendgrid" in l:                                     return "sendgrid"
    if "amplitude" in l:                                    return "amplitude"
    if "segment" in l:                                      return "segment"
    if "heroku" in l:                                       return "heroku"
    # Auto-detect: try slug derivation against known TECH_ICONS
    _slug = re.sub(r"[^a-z0-9]", "", l.replace(".", "dot"))
    if _slug and _slug in TECH_ICONS:                       return _slug
    _slug2 = re.sub(r"[^a-z0-9]", "", l)
    if _slug2 and _slug2 in TECH_ICONS:                     return _slug2
    return None


